function shuffleArray<T>(array: T[]): T[] {
    let currentIndex = array.length;
    let randomIndex: number;
    while (currentIndex !== 0) {
        randomIndex = Math.floor(Math.random() * currentIndex);
        currentIndex--;
        [array[currentIndex], array[randomIndex]] = [
            array[randomIndex],
            array[currentIndex],
        ];
    }
    return array;
}

function TechCard(tech: {
    name: string;
    icon: React.ReactNode;
    bg: React.ReactNode;
}) {
    const id = useId();
    const controls = useAnimation();
    const ref = useRef(null);
    const inView = useInView(ref, { once: true });

    useEffect(() => {
        if (inView) {
            controls.start({
                opacity: 1,
                transition: {
                    delay: Math.random() * 2,
                    ease: 'easeOut',
                    duration: 1,
                },
            });
        }
    }, [controls, inView]);

    return (
        <motion.div
            key={id}
            ref={ref}
            initial={{ opacity: 0 }}
            animate={controls}
            className={cn(
                'relative size-16 sm:size-20 cursor-pointer overflow-hidden rounded-2xl border p-3 sm:p-4',
                // light styles
                'bg-white [box-shadow:0_0_0_1px_rgba(0,0,0,.03),0_2px_4px_rgba(0,0,0,.05),0_12px_24px_rgba(0,0,0,.05)]',
                // dark styles
                'transform-gpu dark:bg-transparent dark:[border:1px_solid_rgba(255,255,255,.1)] dark:[box-shadow:0_-20px_80px_-20px_#ffffff1f_inset]'
            )}
            title={tech.name}
        >
            {tech.icon}
            {tech.bg}
        </motion.div>
    );
}

export function Integrations() {
    const [randomTechs1, setRandomTechs1] = useState<typeof technologies>([]);
    const [randomTechs2, setRandomTechs2] = useState<typeof technologies>([]);
    const [randomTechs3, setRandomTechs3] = useState<typeof technologies>([]);

    useEffect(() => {
        if (typeof window !== 'undefined') {
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setRandomTechs1(shuffleArray([...technologies]));
            setRandomTechs2(shuffleArray([...technologies]));
            setRandomTechs3(shuffleArray([...technologies]));
        }
    }, []);

    return (
        <section className='relative py-16 sm:py-6'>
            <div className='container mx-auto px-4 sm:px-6 lg:px-8'>
                <div className='flex w-full flex-col items-center justify-center'>
                    <div className='relative flex w-full max-w-4xl flex-col items-center justify-center overflow-hidden rounded-xl'>
                        {/* 3 marquees au total */}
                        <Marquee
                            reverse
                            className='-delay-[200ms] [--duration:20s]'
                            repeat={2}
                        >
                            {randomTechs1.map((tech, idx) => (
                                <TechCard key={`tech1-${idx}`} {...tech} />
                            ))}
                        </Marquee>

                        <Marquee
                            reverse
                            className='[--duration:25s]'
                            repeat={2}
                        >
                            {randomTechs2.map((tech, idx) => (
                                <TechCard key={`tech2-${idx}`} {...tech} />
                            ))}
                        </Marquee>

                        <Marquee
                            reverse
                            className='-delay-[200ms] [--duration:22s]'
                            repeat={2}
                        >
                            {randomTechs3.map((tech, idx) => (
                                <TechCard key={`tech3-${idx}`} {...tech} />
                            ))}
                        </Marquee>

                        {/* Gradient overlays pour l'effet de fade */}
                        {/* Fade vertical (haut et bas) */}
                        <div className='absolute inset-x-0 top-0 h-16 bg-gradient-to-b from-background to-transparent pointer-events-none z-10' />
                        <div className='absolute inset-x-0 bottom-0 h-16 bg-gradient-to-t from-background to-transparent pointer-events-none z-10' />

                        {/* Fade horizontal (gauche et droite) */}
                        <div className='absolute inset-y-0 left-0 w-32 bg-gradient-to-r from-background to-transparent pointer-events-none z-10' />
                        <div className='absolute inset-y-0 right-0 w-32 bg-gradient-to-l from-background to-transparent pointer-events-none z-10' />
                    </div>
                </div>
            </div>
        </section>
    );
}
